USE banking;

-- ============================================================
-- THEM 140 KHACH HANG (CustomerID 11-150)
-- ============================================================

-- ============================================================
-- THEM 140 TAI KHOAN (AccountID 11-150)
-- ============================================================

-- ============================================================
-- THEM 10 NHAN VIEN (EmployeeID 11-20)
-- ============================================================

-- ============================================================
-- THEM 140 GIAO DICH (TransactionID 11-150)
-- ============================================================

-- ============================================================
-- KIEM TRA SO LUONG SAU KHI THEM
-- ============================================================
SELECT 'Customers'   AS Bang, COUNT(*) AS SoLuong FROM Customers
UNION SELECT 'Accounts',    COUNT(*) FROM Accounts
UNION SELECT 'Employees',   COUNT(*) FROM Employees
UNION SELECT 'Transactions',COUNT(*) FROM Transactions;